// The callback must return a truthy or falsy value — that is the 'test'.
// The index and array arguments are optional; most calls only use element.

// Quick mental model:
//   some  =  OR across all elements  (true if ANY passes)
//   every =  AND across all elements (true only if ALL pass)

const numbers = [2, 7, 4, 1];

// Is any number greater than 5?
numbers.some(n => n > 5);  // true  (7 passes — stops there)

// Is any number negative?
numbers.some(n => n < 0);  // false (no element passes — all four checked)

// With objects:
const users = [
  { name: 'Alice', admin: false },
  { name: 'Bob',   admin: true  },
  { name: 'Carol', admin: false },
];
users.some(u => u.admin);  // true  (Bob passes — Carol never checked)

// Checking for existence by value:
const tags = ['react', 'javascript', 'typescript'];
tags.some(t => t === 'typescript');  // true
tags.some(t => t === 'python');      // false

// Using index:
const items = [10, 20, 30, 40];
// Are there duplicate-adjacent values?
items.some((item, i) => i > 0 && item === items[i - 1]); // false

const scores = [88, 92, 76, 95];

// Did every student pass (≥ 60)?
scores.every(s => s >= 60);  // true  (all four pass)

// Did every student score above 80?
scores.every(s => s > 80);   // false (76 fails — 95 never checked)

// With objects:
const items = [
  { name: 'Laptop', inStock: true  },
  { name: 'Mouse',  inStock: true  },
  { name: 'Desk',   inStock: false },
];
items.every(item => item.inStock);  // false

// Validate a list of email-like strings:
const emails = ['a@b.com', 'user@example.org', 'invalid'];
emails.every(e => e.includes('@'));  // false ('invalid' fails)

// Ensure all IDs are positive integers:
const ids = [1, 5, 12, 7];
ids.every(id => Number.isInteger(id) && id > 0);  // true

// Verify short-circuit with a side effect:
const visitedSome = [];
[2, 7, 4, 1].some(n => {
  visitedSome.push(n);
  return n > 5;
});
console.log(visitedSome); // [2, 7] — only two elements visited

const visitedEvery = [];
[6, 8, 3, 9].every(n => {
  visitedEvery.push(n);
  return n > 5;
});
console.log(visitedEvery); // [6, 8, 3] — stopped when 3 failed, 9 never visited

[].some(n => n > 5);   // false — no element passes (vacuously false)
[].every(n => n > 5);  // true  — no element fails  (vacuously true)

// The every() result might feel counterintuitive, but the logic is consistent:
// 'every element passes' is true unless a counterexample exists — and none do.

// Guarded version — only 'all pass' when there is at least one item:
function allPass(arr, fn) {
  return arr.length > 0 && arr.every(fn);
}

allPass([], n => n > 5);    // false — correct for most business logic
allPass([6, 8], n => n > 5); // true

// Similarly for 'requires at least one':
function requiresAny(arr, fn) {
  return arr.length > 0 && arr.some(fn);
}

import { useState } from 'react';

const REQUIRED_FIELDS = ['username', 'email', 'password'];

function SignupForm() {
  const [fields, setFields] = useState({
    username: '',
    email: '',
    password: '',
  });

  // Disable submit unless ALL required fields are filled:
  const allFilled = REQUIRED_FIELDS.every(key => fields[key].trim() !== '');

  // Show a warning if ANY field is still empty:
  const anyEmpty = REQUIRED_FIELDS.some(key => fields[key].trim() === '');

  function handleChange(e) {
    setFields(prev => ({ ...prev, [e.target.name]: e.target.value }));
  }

  return (
    <form>
      {anyEmpty && (
        <p className="warning">Please fill in all fields.</p>
      )}
      {REQUIRED_FIELDS.map(key => (
        <input
          key={key}
          name={key}
          placeholder={key}
          value={fields[key]}
          onChange={handleChange}
        />
      ))}
      <button type="submit" disabled={!allFilled}>
        Create account
      </button>
    </form>
  );
}

function CartSummary({ items }) {
  const allAvailable = items.every(item => item.inStock);
  const someOnSale   = items.some(item => item.discounted);
  const hasDigital   = items.some(item => item.type === 'digital');

  return (
    <div>
      {someOnSale && (
        <p className="sale-badge">Sale items in cart!</p>
      )}

      {!allAvailable && (
        <p className="warning">
          One or more items are out of stock and will be removed at checkout.
        </p>
      )}

      {hasDigital && (
        <p className="info">Digital items will be sent to your email.</p>
      )}

      <button disabled={!allAvailable}>Proceed to checkout</button>
    </div>
  );
}

