// Are ANY high-value (> 100) orders still pending?
orders
  .filter(o => o.amount > 100)
  .some(o => o.status === 'pending');  // true (order 3)

// Have ALL priority orders shipped or been delivered?
orders
  .filter(o => o.priority)
  .every(o => o.status === 'shipped' || o.status === 'delivered');  // false (orders 2 and 3 are pending)

// Are there any orders that require attention (pending + priority)?
const urgent = orders.filter(o => o.status === 'pending' && o.priority);
const hasUrgent = urgent.length > 0; // cleaner than: orders.some(o => ...) when you need the items too

// Vitest / Jest — testing utility functions built on some()/every()
import { describe, it, expect } from 'vitest';

function hasAdminUser(users) {
  return users.some(u => u.role === 'admin');
}

function allVerified(users) {
  return users.every(u => u.verified);
}

describe('hasAdminUser', () => {
  it('returns true when at least one admin exists', () => {
    const users = [
      { role: 'user', verified: true  },
      { role: 'admin', verified: true },
    ];
    expect(hasAdminUser(users)).toBe(true);
  });

  it('returns false for an empty list', () => {
    expect(hasAdminUser([])).toBe(false);
  });

  it('returns false when no admin exists', () => {
    expect(hasAdminUser([{ role: 'user', verified: true }])).toBe(false);
  });
});

describe('allVerified', () => {
  it('returns true when all users are verified', () => {
    const users = [{ role: 'user', verified: true }, { role: 'admin', verified: true }];
    expect(allVerified(users)).toBe(true);
  });

  it('returns false when any user is unverified', () => {
    const users = [{ role: 'user', verified: true }, { role: 'admin', verified: false }];
    expect(allVerified(users)).toBe(false);
  });

  // Document the empty-array edge case explicitly:
  it('returns true (vacuously) for an empty array', () => {
    expect(allVerified([])).toBe(true);
  });
});

const numbers = [1, 2, 3, 4, 5];

// ❌ some()/every() return boolean — cannot chain array methods on them:
const result = numbers.some(n => n > 2).map(n => n * 2); // TypeError: not a function

// ✅ Use filter() when you need matching elements:
const greaterThanTwo = numbers.filter(n => n > 2); // [3, 4, 5]

// ✅ Use some() only for the boolean question:
const anyGtTwo = numbers.some(n => n > 2); // true

const users = [{ id: 1, name: 'Alice' }, { id: 2, name: 'Bob' }];

// ❌ some() tells you IF a match exists — not which element:
const found = users.some(u => u.id === 2); // true, but you can't get 'Bob' from this

// ✅ Use find() to retrieve the element:
const bob = users.find(u => u.id === 2); // { id: 2, name: 'Bob' } or undefined

// ❌ Callbacks for some()/every() should be pure predicates.
// Side effects inside them are confusing because the number of calls is unpredictable.
const log = [];
const anyMatch = items.some(item => {
  log.push(item.name); // ❌ dangerous — you don't know how many items get pushed
  return item.active;
});

// ✅ Check first, then act:
const anyActive = items.some(item => item.active);
if (anyActive) {
  items.filter(item => item.active).forEach(item => log.push(item.name));
}

function OrderActions({ selectedOrders }) {
  // ❌ When selectedOrders is empty, this is true — button appears incorrectly enabled:
  const canShipAll = selectedOrders.every(o => o.status === 'ready');

  // ✅ Guard the empty case:
  const canShipAll =
    selectedOrders.length > 0 &&
    selectedOrders.every(o => o.status === 'ready');

  return (
    <button disabled={!canShipAll}>Ship selected orders</button>
  );
}

// These pairs are equivalent:
arr.every(x => condition(x))   ===  !arr.some(x => !condition(x))
arr.some(x => condition(x))    ===  !arr.every(x => !condition(x))

// Example — both express 'all numbers are positive':
const nums = [1, 2, 3];
nums.every(n => n > 0);        // true
!nums.some(n => n <= 0);       // true — identical result

// In practice, pick whichever reads most naturally.
// 'every n is positive' is clearer than 'no n is non-positive'.

const values = [5, 8, 3, 10, 2];

// Is any value greater than the previous element? (is the sequence ever increasing?)
values.some((v, i) => i > 0 && v > values[i - 1]);
// true — 8 > 5, so yes

// Is every pair in ascending order? (is the array sorted?)
values.every((v, i) => i === 0 || v >= values[i - 1]);
// false — 3 < 8, so no

// Are all items at odd indexes positive?
[1, -2, 3, -4, 5].every((v, i) => i % 2 === 0 || v > 0);
// false — index 1 is -2 (not positive)

import { useMemo } from 'react';

function ProductList({ products, minRating }) {
  // Only recomputes when products or minRating changes:
  const allHighRated = useMemo(
    () => products.every(p => p.rating >= minRating),
    [products, minRating]
  );

  const hasOutOfStock = useMemo(
    () => products.some(p => !p.inStock),
    [products]
  );

  return (
    <div>
      {allHighRated && <p>All products meet the quality bar!</p>}
      {hasOutOfStock && <p>Some products are currently unavailable.</p>}
      <ul>
        {products.map(p => <li key={p.id}>{p.name}</li>)}
      </ul>
    </div>
  );
}
